from matplotlib import pyplot as pltimport numpy as npimport cv2from skimage import measurefrom skimage.segmentation import clear_borderpixels_to_um = 0.454img1 = cv2.imread("../data/Osteosarcoma_01.tif")if img1 is None:    raise FileNotFoundError("Image not loaded. Check your file path.")imgb = img1[:, :, 0]   # blue channelplt.figure()plt.imshow(imgb, cmap="gray")plt.title("Blue Channel")ret, thresh = cv2.threshold(    imgb,    0,    255,    cv2.THRESH_BINARY + cv2.THRESH_OTSU)kernel = np.ones((3, 3), np.uint8)opening = cv2.morphologyEx(    thresh,    cv2.MORPH_OPEN,    kernel,    iterations=1)opening = clear_border(opening)distance = cv2.distanceTransform(    opening,    cv2.DIST_L2,    3)ret2, thresh2 = cv2.threshold(    distance,    0.2 * distance.max(),    255,    0)sure_fg = np.uint8(thresh2)sure_bg = cv2.dilate(opening, kernel, iterations=1)unknown = cv2.subtract(sure_bg, sure_fg)ret3, markers = cv2.connectedComponents(sure_fg)markers = markers + 10markers[unknown == 255] = 0markers = markers.astype(np.int32)markers = cv2.watershed(img1, markers)label_img = markers.copy()label_img[label_img == -1] = 0label_img[label_img == 10] = 0clusters = measure.regionprops(    label_img,    intensity_image=imgb)with open("cell_nuclei_measurement.csv", "w") as output_file:    output_file.write(        "Label,Area_um2,EquivalentDiameter_um,Orientation_deg,"        "MajorAxisLength_um,MinorAxisLength_um,Perimeter_um,"        "MinIntensity,MeanIntensity,MaxIntensity\n"    )    for obj in clusters:        label = obj.label        area = obj.area * pixels_to_um**2        equiv_diameter = obj.equivalent_diameter * pixels_to_um        orientation = obj.orientation * 57.2958        major_axis = obj.major_axis_length * pixels_to_um        minor_axis = obj.minor_axis_length * pixels_to_um        perimeter = obj.perimeter * pixels_to_um        min_intensity = obj.min_intensity        mean_intensity = obj.mean_intensity        max_intensity = obj.max_intensity        output_file.write(            f"{label},{area},{equiv_diameter},{orientation},"            f"{major_axis},{minor_axis},{perimeter},"            f"{min_intensity},{mean_intensity},{max_intensity}\n"        )img2 = color.label2rgb(markers, bg_label =0)plt.figure()plt.imshow(img2)